import { useTranslation } from "react-i18next";
import { Link } from "react-router-dom";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Bot, Settings, ChevronRight, CheckCircle, AlertCircle, Sparkles, Play, Lightbulb, Palette } from "lucide-react";
import { useState } from "react";
import { Skeleton } from "@/components/ui/skeleton";
import { LovableAIDemoDialog } from "@/components/admin/LovableAIDemoDialog";
import { MerchantConsultantDemoDialog } from "@/components/admin/MerchantConsultantDemoDialog";
import { MenuDesignerDemoDialog } from "@/components/admin/MenuDesignerDemoDialog";

interface AIProviderConfig {
  id: string;
  name: string;
  description: string;
  icon: React.ElementType;
  iconColor: string;
  configurable: boolean;
  configPath?: string;
  status?: 'configured' | 'not-configured' | 'no-config-needed';
  modelName?: string;
  hasDemo?: boolean;
  recommended?: boolean;
}

const AdminAIConfigList = () => {
  const { t } = useTranslation();
  const [isLoading, setIsLoading] = useState(false);
  const [lovableAIDemoOpen, setLovableAIDemoOpen] = useState(false);
  const [consultantDemoOpen, setConsultantDemoOpen] = useState(false);
  const [menuDesignerDemoOpen, setMenuDesignerDemoOpen] = useState(false);

  const aiProviders: AIProviderConfig[] = [
    {
      id: 'lovable-ai',
      name: 'Lovable AI',
      description: t("admin.aiConfig.lovableAI.desc", "智能餐厅推荐助手，支持餐厅知识库和位置感知"),
      icon: Sparkles,
      iconColor: "text-purple-500",
      configurable: true,
      configPath: '/admin/ai-config/lovable-ai',
      status: 'configured',
      hasDemo: true,
      recommended: true,
    },
    {
      id: 'ask-xiaoxiong',
      name: t("admin.aiSettings.providers.askXiaoxiong", "小熊AI"),
      description: t("admin.aiSettings.providers.askXiaoxiongDesc", "原有AI接口，直接问答"),
      icon: Bot,
      iconColor: "text-primary",
      configurable: false,
      status: 'no-config-needed',
    },
    {
      id: 'merchant-consultant',
      name: t("admin.aiConfig.consultant.name", "经营顾问"),
      description: t("admin.aiConfig.consultant.desc", "专业餐饮零售经营顾问，提供营销策略、运营诊断、成本控制等建议"),
      icon: Lightbulb,
      iconColor: "text-amber-500",
      configurable: false,
      status: 'configured' as const,
      hasDemo: true,
    },
    {
      id: 'menu-designer',
      name: t("admin.aiConfig.designer.name", "菜单设计师"),
      description: t("admin.aiConfig.designer.desc", "专业菜单设计与策划，提供菜品结构、定价策略、多语言排版等服务"),
      icon: Palette,
      iconColor: "text-violet-500",
      configurable: false,
      status: 'configured' as const,
      hasDemo: true,
    },
  ];

  const getStatusBadge = (provider: AIProviderConfig) => {
    if (provider.status === 'no-config-needed') {
      return (
        <Badge variant="secondary" className="text-xs">
          <CheckCircle className="h-3 w-3 mr-1" />
          {t("admin.aiConfig.noConfigNeeded", "无需配置")}
        </Badge>
      );
    }
    if (provider.status === 'configured') {
      return (
        <Badge variant="default" className="text-xs bg-green-500">
          <CheckCircle className="h-3 w-3 mr-1" />
          {t("admin.aiConfig.configured", "已配置")}
        </Badge>
      );
    }
    return (
      <Badge variant="outline" className="text-xs text-orange-500 border-orange-500">
        <AlertCircle className="h-3 w-3 mr-1" />
        {t("admin.aiConfig.pendingConfig", "待配置")}
      </Badge>
    );
  };

  return (
    <div className="p-6 space-y-6 max-w-4xl mx-auto">
      {/* Header */}
      <div className="flex items-center gap-3">
        <Settings className="h-8 w-8 text-primary" />
        <div>
          <h1 className="text-2xl font-bold">{t("admin.aiConfig.title", "AI配置管理")}</h1>
          <p className="text-muted-foreground">
            {t("admin.aiConfig.subtitle", "管理和配置各个AI服务的模型和参数")}
          </p>
        </div>
      </div>

      {/* AI Providers List */}
      <div className="grid grid-cols-1 gap-4">
        {isLoading ? (
          <>
            <Skeleton className="h-32 w-full" />
            <Skeleton className="h-32 w-full" />
          </>
        ) : (
          aiProviders.map((provider) => (
            <Card 
              key={provider.id} 
              className={`transition-all ${provider.configurable ? 'hover:border-primary/50 cursor-pointer' : ''}`}
            >
              <CardHeader className="pb-3">
                  <div className="flex items-start justify-between">
                  <div className="flex items-center gap-3">
                    <div className={`p-2 rounded-lg bg-muted ${provider.iconColor}`}>
                      <provider.icon className="h-6 w-6" />
                    </div>
                    <div>
                      <CardTitle className="text-lg flex items-center gap-2">
                        {provider.name}
                        {provider.recommended && (
                          <Badge className="text-xs bg-purple-500">{t("admin.aiConfig.recommended", "推荐")}</Badge>
                        )}
                        {getStatusBadge(provider)}
                      </CardTitle>
                      <CardDescription className="mt-1">
                        {provider.description}
                      </CardDescription>
                    </div>
                  </div>
                  
                  <div className="flex items-center gap-2">
                    {provider.hasDemo && (
                      <Button 
                        variant="outline" 
                        size="sm"
                        onClick={() => {
                          if (provider.id === 'lovable-ai') {
                            setLovableAIDemoOpen(true);
                          } else if (provider.id === 'merchant-consultant') {
                            setConsultantDemoOpen(true);
                          } else if (provider.id === 'menu-designer') {
                            setMenuDesignerDemoOpen(true);
                          }
                        }}
                      >
                        <Play className="h-4 w-4 mr-1" />
                        {t("admin.aiConfig.test", "测试")}
                      </Button>
                    )}
                    {provider.configurable && provider.configPath && (
                      <Button variant="outline" size="sm" asChild>
                        <Link to={provider.configPath}>
                          {t("admin.aiConfig.configure", "配置")}
                          <ChevronRight className="h-4 w-4 ml-1" />
                        </Link>
                      </Button>
                    )}
                  </div>
                </div>
              </CardHeader>
              
              {provider.configurable && (
                <CardContent className="pt-0">
                  <div className="bg-muted/30 rounded-lg p-3 text-sm">
                    {provider.modelName ? (
                      <div className="flex items-center gap-2">
                        <span className="text-muted-foreground">{t("admin.aiConfig.currentModel", "当前模型:")}</span>
                        <code className="px-2 py-0.5 bg-background rounded text-xs font-mono">
                          {provider.modelName}
                        </code>
                      </div>
                    ) : (
                      <p className="text-muted-foreground">
                        {t("admin.aiConfig.notConfigured", "尚未配置模型，点击右侧\"配置\"按钮进行设置")}
                      </p>
                    )}
                  </div>
                </CardContent>
              )}
            </Card>
          ))
        )}
      </div>

      {/* Quick Links */}
      <Card className="bg-muted/30">
        <CardContent className="pt-6">
          <div className="flex items-center justify-between">
            <div>
              <p className="font-medium">{t("admin.aiConfig.switchProvider", "需要更改主页使用的AI接口？")}</p>
              <p className="text-sm text-muted-foreground">
                {t("admin.aiConfig.switchProviderDesc", "前往AI管理页面切换主页使用的AI服务提供商")}
              </p>
            </div>
            <Button variant="outline" size="sm" asChild>
              <Link to="/admin/ai-settings">
                {t("admin.aiConfig.goToAIManagement", "前往AI管理")}
                <ChevronRight className="h-4 w-4 ml-1" />
              </Link>
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Lovable AI Demo Dialog */}
      <LovableAIDemoDialog 
        open={lovableAIDemoOpen} 
        onOpenChange={setLovableAIDemoOpen} 
      />

      {/* Merchant Consultant Demo Dialog */}
      <MerchantConsultantDemoDialog
        open={consultantDemoOpen}
        onOpenChange={setConsultantDemoOpen}
      />

      {/* Menu Designer Demo Dialog */}
      <MenuDesignerDemoDialog
        open={menuDesignerDemoOpen}
        onOpenChange={setMenuDesignerDemoOpen}
      />
    </div>
  );
};

export default AdminAIConfigList;
